}

export function allowedCallback(target: string, allowedHosts: string[]): boolean {
  try {
    const parsed = new URL(target);
    return ["http:", "https:"].includes(parsed.protocol) && allowedHosts.includes(parsed.hostname);
  } catch {
    return false;
  }
}

